export const wordBank: Record<Difficulty, TrainingItem[]> = {
  basic,
  intermediate,
  advanced,
};

export function pickWords(difficulty: Difficulty, count: number = 10): TrainingItem[] {
  const pool = wordBank[difficulty];
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}
